function SIG_ensureLayout() {
    SIG_ensureLocalQuickActions();
    SIG_ensureTeacherTableLayout();
    SIG_ensureBaselinePanel();
}

function SIG_openLocalPanel(view, anchorId = '') {
    SIG_ensureLayout();
    const trigger = document.querySelector(`[data-sig-view-btn="${view}"]`);
    SIG_switchView(view, trigger || null);
    SIG_render();
    if (anchorId) {
        setTimeout(() => SIG_scrollIntoView(anchorId), 80);
    }
}

function SIG_normalizeSubjectHeader(header) {
    const text = normalizeSubject(String(header || '').replace(/\s+/g, '').trim());
    const map = {
        '语': '语文',
        '数': '数学',
        '英': '英语',
        '物': '物理',
        '化': '化学',
        '政': '政治',
        '道法': '政治',
        '历': '历史',
        '地': '地理',
        '生': '生物'
    };
    return map[text] || text;
}

function SIG_parseRows(rows, defaultSchool = '本校') {
    if (!Array.isArray(rows) || rows.length < 2) return { rawData: [], subjects: [] };
    const headers = rows[0].map((item) => String(item || '').trim());
    const aliasMap = {
        name: ['姓名', '学生姓名', '学生', 'Name', '考生姓名'],
        class: ['班级', '班', '班次', 'Class', '行政班'],
        school: ['学校', 'school', 'School', '校区'],
        total: ['总分', '五科总', '全科总', '总成绩', '合计']
    };
    const idxMap = { name: -1, class: -1, school: -1, total: -1, scores: {} };
    const excludeKeywords = ['排名', '名次', '赋分', '标准分', 'T分', '等级', '分差', 'Z值', '百分位'];
    headers.forEach((header, index) => {
        const text = header.replace(/\s+/g, '');
        Object.entries(aliasMap).forEach(([key, aliases]) => {
            if (aliases.some((alias) => text.includes(alias))) idxMap[key] = index;
        });
        const normalizedSubject = SIG_normalizeSubjectHeader(text);
        if (normalizedSubject && !excludeKeywords.some((keyword) => text.includes(keyword)) && SUBJECT_ORDER.includes(normalizedSubject)) {
            if (!idxMap.scores[normalizedSubject]) idxMap.scores[normalizedSubject] = [];
            idxMap.scores[normalizedSubject].push(index);
        }
    });

    const subjects = Object.keys(idxMap.scores).filter(Boolean);
    const rawData = [];
    for (let rowIndex = 1; rowIndex < rows.length; rowIndex += 1) {
        const row = rows[rowIndex];
        if (!row || !row.length) continue;
        const name = String(idxMap.name >= 0 ? (row[idxMap.name] || '') : '').replace(/\s+/g, '').trim();
        if (!name) continue;
        const className = normalizeClass(idxMap.class >= 0 ? row[idxMap.class] : '未分班');
        const schoolName = String(idxMap.school >= 0 ? (row[idxMap.school] || defaultSchool) : defaultSchool).trim() || defaultSchool;
        const student = {
            name,
            class: className || '未分班',
            school: schoolName,
            scores: {},
            total: 0,
            hasValidScore: false
        };
        subjects.forEach((subject) => {
            const indices = idxMap.scores[subject] || [];
            let sum = 0;
            let valid = false;
            indices.forEach((columnIndex) => {
                const value = parseFloat(String(row[columnIndex] ?? '').replace(/\s+/g, ''));
                if (Number.isFinite(value)) {
                    sum += value;
                    valid = true;
                }
            });
            if (valid) {
                student.scores[subject] = parseFloat(sum.toFixed(2));
                student.total += sum;
                student.hasValidScore = true;
            }
        });
        if (!student.hasValidScore && idxMap.total >= 0) {
            const totalValue = parseFloat(String(row[idxMap.total] ?? '').replace(/\s+/g, ''));
            if (Number.isFinite(totalValue)) {
                student.total = totalValue;
                student.hasValidScore = true;
            }
        }
        student.total = parseFloat(student.total.toFixed(2));
        if (student.hasValidScore) rawData.push(student);
    }
    return { rawData, subjects };
}

function SIG_buildSchoolMap(rawData) {
    const schools = {};
    (rawData || []).forEach((student) => {
        const schoolName = String(student.school || '本校').trim() || '本校';
        if (!schools[schoolName]) schools[schoolName] = { name: schoolName, students: [] };
        schools[schoolName].students.push(student);
    });
    return schools;
}

async function SIG_handleFile(input) {
    const file = input?.files?.[0];
    if (!file) return;
    if (typeof XLSX === 'undefined') {
        alert('请刷新页面后再导入 Excel');
        return;
    }
    const buffer = await file.arrayBuffer();
    const workbook = XLSX.read(buffer, { type: 'array' });
    let parsed = [];
    workbook.SheetNames.forEach((sheetName) => {
        const rows = XLSX.utils.sheet_to_json(workbook.Sheets[sheetName], { header: 1 });
        const result = SIG_parseRows(rows, sheetName);
        parsed.push(...result.rawData);
    });
    SIG_LOCAL_STATE = {
        imported: parsed.length > 0,
        source: parsed.length > 0 ? 'upload' : 'workspace',
        rawData: parsed,
        schools: SIG_buildSchoolMap(parsed)
    };
    const status = document.getElementById('sigImportStatus');
    const badge = document.getElementById('sigSourceBadge');
    if (status) {
        status.textContent = parsed.length
            ? `已导入专属成绩文件：${file.name}，共 ${parsed.length} 条有效成绩。此数据仅在“校内成绩”模块本地使用。`
            : '文件中未识别到有效成绩数据，请检查列名与内容。';
    }
    if (badge) badge.textContent = parsed.length ? '当前来源：专属文件' : '当前来源：工作区';
    SIG_switchView('teaching', document.querySelector('[data-sig-view-btn="teaching"]'));
    SIG_render();
    input.value = '';
}

function SIG_getSourceState() {
    if (SIG_LOCAL_STATE.imported && SIG_LOCAL_STATE.rawData.length) {
        return {
            source: 'upload',
            rawData: SIG_LOCAL_STATE.rawData,
            schools: SIG_LOCAL_STATE.schools,
            schoolOptions: Object.keys(SIG_LOCAL_STATE.schools || {})
        };
    }
    const schools = {};
    Object.keys(SCHOOLS || {}).forEach((schoolName) => {
        const school = SCHOOLS[schoolName];
        if (!school || !Array.isArray(school.students)) return;
        schools[schoolName] = {
            name: schoolName,
            students: school.students.filter((student) => student.hasValidScore || SIG_toNumber(student.total, 0) > 0)
        };
    });
    return {
        source: 'workspace',
        rawData: Object.values(schools).flatMap((school) => school.students),
        schools,
        schoolOptions: Object.keys(schools)
    };
}

function SIG_getAccessibleSchools() {
    const user = getCurrentUser();
    const source = SIG_getSourceState();
    const schools = source.schoolOptions.length ? source.schoolOptions : Object.keys(source.schools || {});
    return (window.PermissionPolicy && typeof PermissionPolicy.getAccessibleSchoolNames === 'function')
        ? PermissionPolicy.getAccessibleSchoolNames(user, schools)
        : schools;
}

function SIG_updateSchoolSelect() {
    const schools = SIG_getAccessibleSchools();
    ['sigSchoolSelect', 'sigSchoolSelectAlt'].forEach((id) => {
        const sel = document.getElementById(id);
        if (!sel) return;
        const old = sel.value;
        sel.innerHTML = schools.map((school) => `<option value="${school}">${school}</option>`).join('');
        const fallback = old && schools.includes(old)
            ? old
            : (MY_SCHOOL && schools.includes(MY_SCHOOL) ? MY_SCHOOL : (schools[0] || ''));
        if (fallback) sel.value = fallback;
    });
    return document.getElementById('sigSchoolSelect')?.value || schools[0] || '';
}

function SIG_getSchoolStudents(schoolName) {
    const source = SIG_getSourceState();
    const school = source.schools?.[schoolName];
    const rows = Array.isArray(school?.students) ? school.students.slice() : [];
    const user = getCurrentUser();
    const mode = window.PermissionPolicy && PermissionPolicy.isClassTeacher(user) ? 'homeroom' : 'teaching';
    return (window.PermissionPolicy && typeof PermissionPolicy.filterStudentRows === 'function')
        ? PermissionPolicy.filterStudentRows(user, rows, { mode })
        : rows;
}

function SIG_buildThresholds(students) {
    const scores = (students || [])
        .map((student) => SIG_toNumber(student.total, NaN))
        .filter((score) => Number.isFinite(score))
        .sort((a, b) => b - a);
    if (!scores.length) return { highLine: 0, stableLine: 0 };
    return {
        highLine: scores[Math.max(0, Math.floor(scores.length * 0.25) - 1)] || 0,
        stableLine: scores[Math.min(scores.length - 1, Math.floor(scores.length * 0.8))] || 0
    };
}

function SIG_buildClassRows(students) {
    const thresholds = SIG_buildThresholds(students);
    const buckets = {};
    (students || []).forEach((student) => {
        const cls = normalizeClass(student.class || '');
        if (!cls) return;
        if (!buckets[cls]) buckets[cls] = [];
        buckets[cls].push(SIG_toNumber(student.total, 0));
    });
    const rows = Object.entries(buckets).map(([className, scores]) => {
        const count = scores.length;
        const avg = count ? scores.reduce((sum, score) => sum + score, 0) / count : 0;
        const highRate = count ? scores.filter((score) => score >= thresholds.highLine).length / count : 0;
        const stableRate = count ? scores.filter((score) => score >= thresholds.stableLine).length / count : 0;
        return { className, count, avg, highRate, stableRate, score: 0 };
    });
    const maxAvg = Math.max(...rows.map((row) => row.avg), 0) || 1;
    const maxHigh = Math.max(...rows.map((row) => row.highRate), 0) || 1;
    const maxStable = Math.max(...rows.map((row) => row.stableRate), 0) || 1;
    rows.forEach((row) => {
        row.score = ((row.avg / maxAvg) * 35) + ((row.highRate / maxHigh) * 35) + ((row.stableRate / maxStable) * 30);
    });
    rows.sort((a, b) => b.score - a.score);
    rows.forEach((row, index) => { row.rank = index + 1; });
    return { rows, thresholds };
}

function SIG_sameSchool(left, right) {
    const a = String(left || '').trim();
    const b = String(right || '').trim();
    if (!a || !b) return false;
    return (typeof areSchoolNamesEquivalent === 'function') ? areSchoolNamesEquivalent(a, b) : a === b;
}

function SIG_sameExam(left, right) {
    const a = String(left || '').trim();
    const b = String(right || '').trim();
    if (!a || !b) return false;
    return (typeof isExamKeyEquivalentForCompare === 'function') ? isExamKeyEquivalentForCompare(a, b) : a === b;
}

function SIG_cleanName(value) {
    if (typeof getProgressCleanName === 'function') return getProgressCleanName(value);
    return String(value || '').replace(/\s+/g, '').replace(/[^\u4e00-\u9fa5a-zA-Z0-9]/g, '').toLowerCase();
}

function SIG_buildStudentKey(student) {
    const schoolName = String(student?.school || '').trim();
    const className = normalizeClass(student?.class || '');
    const cleanName = SIG_cleanName(student?.name);
    return `${schoolName}__${className}__${cleanName}`;
}

function SIG_filterStudentRows(rows) {
    const user = getCurrentUser();
    const mode = window.PermissionPolicy && PermissionPolicy.isClassTeacher(user) ? 'homeroom' : 'teaching';
    return (window.PermissionPolicy && typeof PermissionPolicy.filterStudentRows === 'function')
        ? PermissionPolicy.filterStudentRows(user, Array.isArray(rows) ? rows : [], { mode })
        : (Array.isArray(rows) ? rows.slice() : []);
}

function SIG_buildClassSchoolMap(source) {
    const map = {};
    Object.entries(source?.schools || {}).forEach(([schoolName, school]) => {
        (school?.students || []).forEach((student) => {
            const className = normalizeClass(student?.class || '');
            if (className && !map[className]) map[className] = schoolName;
        });
    });
    const fallback = (typeof getClassSchoolMapForAllData === 'function') ? (getClassSchoolMapForAllData() || {}) : {};
    Object.entries(fallback).forEach(([className, schoolName]) => {
        const normalizedClass = normalizeClass(className);
        if (normalizedClass && schoolName && !map[normalizedClass]) map[normalizedClass] = schoolName;
    });
    return map;
}

function SIG_getSubjectThresholds(subjectName, rows) {
    const config = THRESHOLDS?.[subjectName] || {};
    const scores = (rows || [])
        .map((row) => SIG_toNumber(row?.scores?.[subjectName], NaN))
        .filter((score) => Number.isFinite(score))
        .sort((a, b) => b - a);
    let excellent = SIG_toNumber(config.exc, NaN);
    let pass = SIG_toNumber(config.pass, NaN);
    if (!Number.isFinite(excellent) && scores.length) {
        excellent = scores[Math.max(0, Math.floor(scores.length * 0.25) - 1)] || 0;
    }
    if (!Number.isFinite(pass) && scores.length) {
        pass = scores[Math.min(scores.length - 1, Math.floor(scores.length * 0.8))] || 60;
    }
    if (!Number.isFinite(excellent)) excellent = 0;
    if (!Number.isFinite(pass)) pass = 60;
    return {
        excellent,
        pass,
        low: Math.max(0, pass * 0.6)
    };
}

function SIG_buildMetricSummary(rows, subjectName, thresholds) {
    const scores = (rows || [])
        .map((row) => SIG_toNumber(row?.scores?.[subjectName], NaN))
        .filter((score) => Number.isFinite(score));
    if (!scores.length) {
        return {
            count: 0,
            avg: 0,
            excellentRate: 0,
            passRate: 0,
            lowRate: 0
        };
    }
    const total = scores.reduce((sum, score) => sum + score, 0);
    return {
        count: scores.length,
        avg: total / scores.length,
        excellentRate: scores.filter((score) => score >= thresholds.excellent).length / scores.length,
        passRate: scores.filter((score) => score >= thresholds.pass).length / scores.length,
        lowRate: scores.filter((score) => score < thresholds.low).length / scores.length
    };
}

function SIG_normalizeBaselineRows(rows, examId = '') {
    return (rows || []).map((row) => {
        const student = row?.student || {};
        const scores = {};
        Object.entries(row?.scores || student?.scores || {}).forEach(([subject, value]) => {
            const normalizedSubject = normalizeSubject(subject);
            const score = SIG_toNumber(value, NaN);
            if (normalizedSubject && Number.isFinite(score)) {
                scores[normalizedSubject] = score;
            }
        });
        let total = SIG_toNumber(
            row?.total ?? row?.totalScore ?? row?.score ?? student?.total ?? student?.totalScore,
            NaN
        );
        if (!Number.isFinite(total) && Object.keys(scores).length) {
            total = Object.values(scores).reduce((sum, score) => sum + SIG_toNumber(score, 0), 0);
        }
        const normalized = {
            name: String(row?.name || student?.name || '').trim(),
            school: String(row?.school || student?.school || '').trim(),
            class: normalizeClass(row?.class || student?.class || ''),
            total: Number.isFinite(total) ? total : 0,
            scores,
            examId: examId || row?.examFullKey || row?.examId || ''
        };
        return normalized.name && normalized.school && normalized.class && (Object.keys(scores).length || Number.isFinite(total))
            ? normalized
            : null;
    }).filter(Boolean);
}

function SIG_getBaselineExamEntries(schoolName) {
    const db = window.COHORT_DB || ((typeof CohortDB !== 'undefined' && typeof CohortDB.ensure === 'function') ? CohortDB.ensure() : null);
    return Object.values(db?.exams || {})
        .map((exam) => {
            const examId = String(exam?.examId || '').trim();
            const examFullKey = String(exam?.examFullKey || examId).trim();
            const rows = SIG_filterStudentRows(
                SIG_normalizeBaselineRows(exam?.data || [], examFullKey || examId).filter((row) => (
                    !schoolName || SIG_sameSchool(row.school, schoolName)
                ))
            );
            return {
                examId,
                examFullKey,
                createdAt: Number(exam?.createdAt || exam?.updatedAt || 0),
                rows
            };
        })
        .filter((exam) => (exam.examId || exam.examFullKey) && exam.rows.length > 0)
        .filter((exam) => !CURRENT_EXAM_ID || !SIG_sameExam(exam.examId || exam.examFullKey, CURRENT_EXAM_ID))
        .sort((a, b) => (b.createdAt || 0) - (a.createdAt || 0));
}

function SIG_getTeacherAssignments(source, schoolName, students) {
    if (window.DataManager && typeof DataManager.ensureTeacherMap === 'function') {
        DataManager.ensureTeacherMap(false);
    }
    const teacherMap = window.TEACHER_MAP || {};
    const teacherSchoolMap = window.TEACHER_SCHOOL_MAP || {};
    const classSchoolMap = SIG_buildClassSchoolMap(source);
    const localClassSet = new Set((students || []).map((student) => normalizeClass(student?.class || '')).filter(Boolean));
    return Object.entries(teacherMap).map(([key, teacherName]) => {
        const parts = String(key || '').split('_');
        const className = normalizeClass(parts.shift() || '');
        const subjectName = normalizeSubject(parts.join('_'));
        const mappedSchool = String(teacherSchoolMap[key] || classSchoolMap[className] || '').trim();
        return {
            key,
            teacherName: String(teacherName || '').trim(),
            className,
            subjectName,
            schoolName: mappedSchool
        };
    }).filter((item) => {
        if (!item.teacherName || !item.className || !item.subjectName) return false;
        if (!schoolName) return true;
        if (item.schoolName) return SIG_sameSchool(item.schoolName, schoolName);
        return localClassSet.has(item.className);
    });
}

function SIG_buildTeacherProtection(classes, subjectName, teacherName) {
    const db = window.COHORT_DB || ((typeof CohortDB !== 'undefined' && typeof CohortDB.ensure === 'function') ? CohortDB.ensure() : null);
    const history = db?.teachingHistory || {};
    const currentTermId = String(
        (typeof getPreferredTeacherTermId === 'function' ? getPreferredTeacherTermId() : '')
        || readCurrentTeacherTermId()
        || ''
    ).trim();
    const classList = [...new Set((classes || []).map((item) => normalizeClass(item)).filter(Boolean))];
    const normalizedTeacher = typeof normalizeTeacherName === 'function'
        ? normalizeTeacherName(teacherName)
        : String(teacherName || '').replace(/\s+/g, '');
    const historyEntries = Object.entries(history)
        .filter(([termId]) => String(termId || '').trim() && String(termId || '').trim() !== currentTermId)
        .sort((a, b) => String(b[0]).localeCompare(String(a[0]), 'zh-CN', { numeric: true }))
        .slice(0, 3);
    return historyEntries.some(([, entry]) => {
        const map = entry?.map && typeof entry.map === 'object' ? entry.map : (entry || {});
        return classList.some((className) => {
            const historyTeacher = String(map?.[`${className}_${subjectName}`] || '').trim();
            if (!historyTeacher) return false;
            const normalizedHistoryTeacher = typeof normalizeTeacherName === 'function'
                ? normalizeTeacherName(historyTeacher)
                : historyTeacher.replace(/\s+/g, '');
            return normalizedHistoryTeacher && normalizedHistoryTeacher !== normalizedTeacher;
        });
    });
}

function SIG_buildConversionMetrics(currentRows, subjectName, baselineRows) {
    const neutral = {
        score: 50,
        adjustment: 0,
        matchedCount: 0,
        previousCount: baselineRows.length,
        stabilityRate: 0
    };
    if (!baselineRows.length || !currentRows.length) return neutral;

    const currentThresholds = SIG_getSubjectThresholds(subjectName, currentRows);
    const baselineThresholds = SIG_getSubjectThresholds(subjectName, baselineRows);
    const baselineMap = new Map(baselineRows.map((row) => [SIG_buildStudentKey(row), row]));
    let matchedCount = 0;
    let excellentPool = 0;
    let excellentHold = 0;
    let edgeExcellentPool = 0;
    let edgeExcellentHit = 0;
    let edgePassPool = 0;
    let edgePassHit = 0;
    let lowPool = 0;
    let lowLift = 0;
    let totalChange = 0;

    currentRows.forEach((student) => {
        const baselineRow = baselineMap.get(SIG_buildStudentKey(student));
        if (!baselineRow) return;
        const currentScore = SIG_toNumber(student?.scores?.[subjectName], NaN);
        const baselineScore = SIG_toNumber(baselineRow?.scores?.[subjectName], NaN);
        if (!Number.isFinite(currentScore) || !Number.isFinite(baselineScore)) return;
        matchedCount += 1;
        totalChange += currentScore - baselineScore;

        if (baselineScore >= baselineThresholds.excellent) {
            excellentPool += 1;
            if (currentScore >= currentThresholds.excellent) excellentHold += 1;
        }
        if (baselineScore >= baselineThresholds.excellent - 5 && baselineScore < baselineThresholds.excellent) {
            edgeExcellentPool += 1;
            if (currentScore >= currentThresholds.excellent) edgeExcellentHit += 1;
        }
        if (baselineScore >= baselineThresholds.pass - 5 && baselineScore < baselineThresholds.pass) {
            edgePassPool += 1;
            if (currentScore >= currentThresholds.pass) edgePassHit += 1;
        }
        if (baselineScore < baselineThresholds.low) {
            lowPool += 1;
            if (currentScore >= currentThresholds.low) lowLift += 1;
        }
    });

    if (!matchedCount) return neutral;

    const rates = [
        excellentPool ? excellentHold / excellentPool : null,
        edgeExcellentPool ? edgeExcellentHit / edgeExcellentPool : null,
        edgePassPool ? edgePassHit / edgePassPool : null,
        lowPool ? lowLift / lowPool : null
    ].filter((value) => value !== null);
    const rateScore = rates.length
        ? (rates.reduce((sum, value) => sum + value, 0) / rates.length) * 100
        : 50;
    const avgChange = totalChange / matchedCount;
    const reliability = Math.max(0, Math.min(1, matchedCount / Math.max(currentRows.length, baselineRows.length, 1))) * Math.min(1, matchedCount / 12);
    const score = Math.max(0, Math.min(100, 50 + ((rateScore - 50) * reliability) + (Math.max(-8, Math.min(8, avgChange / 3)) * reliability)));
    return {
        score,
        adjustment: Math.max(-12, Math.min(12, (score - 50) * 0.35)),
        matchedCount,
        previousCount: baselineRows.length,
        stabilityRate: Math.max(0, Math.min(1, matchedCount / Math.max(currentRows.length, baselineRows.length, 1)))
    };
}

function SIG_buildRollingConversionMetrics(currentRows, subjectName, baselineExams) {
    const entries = (baselineExams || []).slice(0, 3);
    if (!entries.length) return SIG_buildConversionMetrics(currentRows, subjectName, []);

    const weighted = entries.map((entry, index) => {
        const metrics = SIG_buildConversionMetrics(currentRows, subjectName, entry?.rows || []);
        const recencyWeight = Math.max(0.55, 1 - (index * 0.2));
        const sampleWeight = Math.max(0.35, Math.min(1, SIG_toNumber(metrics.matchedCount, 0) / 15));
        return {
            label: String(entry?.examFullKey || entry?.examId || `baseline_${index + 1}`),
            metrics,
            weight: SIG_toNumber(metrics.matchedCount, 0) > 0 ? (recencyWeight * sampleWeight) : 0
        };
    }).filter((item) => item.weight > 0);

    if (!weighted.length) {
        const latest = SIG_buildConversionMetrics(currentRows, subjectName, entries[0]?.rows || []);
        return {
            ...latest,
            baselineCount: entries.filter((entry) => Array.isArray(entry?.rows) && entry.rows.length > 0).length,
            labels: entries.map((entry, index) => String(entry?.examFullKey || entry?.examId || `baseline_${index + 1}`))
        };
    }

    const totalWeight = weighted.reduce((sum, item) => sum + item.weight, 0) || 1;
    const blend = (getter, fallback = 0) => {
        const value = weighted.reduce((sum, item) => sum + (getter(item.metrics) * item.weight), 0) / totalWeight;
        return Number.isFinite(value) ? value : fallback;
    };
    return {
        score: Math.max(0, Math.min(100, blend((metrics) => SIG_toNumber(metrics.score, 50), 50))),
        adjustment: Math.max(-12, Math.min(12, blend((metrics) => SIG_toNumber(metrics.adjustment, 0), 0))),
        matchedCount: Math.round(blend((metrics) => SIG_toNumber(metrics.matchedCount, 0), 0)),
        previousCount: Math.round(blend((metrics) => SIG_toNumber(metrics.previousCount, 0), 0)),
        stabilityRate: Math.max(0, Math.min(1, blend((metrics) => SIG_toNumber(metrics.stabilityRate, 0), 0))),
        baselineCount: weighted.length,
        labels: weighted.map((item) => item.label)
    };
}

function SIG_normalizePeerMetric(value, values, reverse = false) {
    const list = (values || []).map((item) => SIG_toNumber(item, NaN)).filter((item) => Number.isFinite(item));
    if (!list.length) return 0.5;
    const min = Math.min(...list);
    const max = Math.max(...list);
    if (!Number.isFinite(min) || !Number.isFinite(max) || Math.abs(max - min) < 0.0001) return 0.5;
    const normalized = reverse ? ((max - value) / (max - min)) : ((value - min) / (max - min));
    return Math.max(0, Math.min(1, normalized));
}

function SIG_filterTeacherRows(rows, schoolName) {
    const user = getCurrentUser();
    if (!(window.PermissionPolicy && typeof PermissionPolicy.canQueryTeacherMetric === 'function')) {
        return Array.isArray(rows) ? rows.slice() : [];
    }
    return (Array.isArray(rows) ? rows : []).filter((row) => (
        PermissionPolicy.canQueryTeacherMetric(user, row.teacherName, { classes: row.classesText }, schoolName)
    ));
}

function SIG_formatBaselineTime(timestamp) {
    const time = SIG_toNumber(timestamp, NaN);
    if (!Number.isFinite(time) || time <= 0) return '本地快照';
    try {
        return new Date(time).toLocaleString('zh-CN', {
            month: '2-digit',
            day: '2-digit',
            hour: '2-digit',
            minute: '2-digit'
        });
    } catch (error) {
        return '本地快照';
    }
}

function SIG_buildBaselineSummary(baselineExams, students) {
    const currentKeys = new Set((students || []).map((student) => SIG_buildStudentKey(student)));
    return (baselineExams || []).slice(0, 5).map((entry, index) => {
        const rows = Array.isArray(entry?.rows) ? entry.rows : [];
        const matchedCount = rows.reduce((sum, row) => sum + (currentKeys.has(SIG_buildStudentKey(row)) ? 1 : 0), 0);
        const subjectCount = new Set(rows.flatMap((row) => (
            Object.keys(row?.scores || {}).map((subject) => normalizeSubject(subject)).filter(Boolean)
        ))).size;
        return {
            examLabel: String(entry?.examFullKey || entry?.examId || `历史基线${index + 1}`),
            createdAtText: SIG_formatBaselineTime(entry?.createdAt),
            sampleCount: rows.length,
            matchedCount,
            matchedRate: rows.length ? (matchedCount / rows.length) : 0,
            subjectCount
        };
    });
}

function SIG_buildTeacherRows(schoolName, students, baselineExams, source) {
    const subjectSet = new Set(
        (students || []).flatMap((student) => Object.keys(student?.scores || {}).map((subject) => normalizeSubject(subject))).filter(Boolean)
    );
    const assignmentGroups = {};
    SIG_getTeacherAssignments(source, schoolName, students).forEach((item) => {
        if (!subjectSet.has(item.subjectName)) return;
        const groupKey = `${item.teacherName}__${item.subjectName}`;
        if (!assignmentGroups[groupKey]) {
            assignmentGroups[groupKey] = {
                teacherName: item.teacherName,
                subjectName: item.subjectName,
                classes: new Set()
            };
        }
        assignmentGroups[groupKey].classes.add(item.className);
    });

    const baseRows = Object.values(assignmentGroups).map((group) => {
        const classes = [...group.classes].sort((a, b) => String(a).localeCompare(String(b), 'zh-CN', { numeric: true }));
        const classSet = new Set(classes);
        const currentRows = (students || []).filter((student) => (
            classSet.has(normalizeClass(student?.class || ''))
            && Number.isFinite(SIG_toNumber(student?.scores?.[group.subjectName], NaN))
        ));
        if (!currentRows.length) return null;

        const thresholds = SIG_getSubjectThresholds(group.subjectName, students || []);
        const metrics = SIG_buildMetricSummary(currentRows, group.subjectName, thresholds);
        const baselineSeries = (baselineExams || []).slice(0, 3).map((entry) => ({
            ...entry,
            rows: (entry?.rows || []).filter((row) => (
                classSet.has(normalizeClass(row?.class || ''))
                && Number.isFinite(SIG_toNumber(row?.scores?.[group.subjectName], NaN))
            ))
        })).filter((entry) => entry.rows.length > 0);
        const conversion = SIG_buildRollingConversionMetrics(currentRows, group.subjectName, baselineSeries);
        const protectedByTeacherChange = SIG_buildTeacherProtection(classes, group.subjectName, group.teacherName);
        return {
            teacherName: group.teacherName,
            subjectName: group.subjectName,
            classes,
            classesText: classes.join('、'),
            metrics,
            conversion,
            teacherChangeProtected: protectedByTeacherChange
        };
    }).filter(Boolean);

    const peerMap = {};
    baseRows.forEach((row) => {
        if (!peerMap[row.subjectName]) {
            peerMap[row.subjectName] = { avg: [], excellentRate: [], passRate: [], lowRate: [] };
        }
        peerMap[row.subjectName].avg.push(row.metrics.avg);
        peerMap[row.subjectName].excellentRate.push(row.metrics.excellentRate);
        peerMap[row.subjectName].passRate.push(row.metrics.passRate);
        peerMap[row.subjectName].lowRate.push(row.metrics.lowRate);
    });

    const rows = SIG_filterTeacherRows(baseRows.map((row) => {
        const peer = peerMap[row.subjectName] || { avg: [], excellentRate: [], passRate: [], lowRate: [] };
        const avgNorm = SIG_normalizePeerMetric(row.metrics.avg, peer.avg);
        const excellentNorm = SIG_normalizePeerMetric(row.metrics.excellentRate, peer.excellentRate);
        const passNorm = SIG_normalizePeerMetric(row.metrics.passRate, peer.passRate);
        const lowNorm = SIG_normalizePeerMetric(row.metrics.lowRate, peer.lowRate, true);
        const currentScore = (avgNorm * 40) + (excellentNorm * 20) + (passNorm * 20) + (lowNorm * 20);
        const sampleWeight = Math.max(0.55, Math.min(1, row.metrics.count / 25));
        const conversionAdjustment = row.teacherChangeProtected
            ? Math.max(0, SIG_toNumber(row.conversion.adjustment, 0))
            : SIG_toNumber(row.conversion.adjustment, 0);
        const fairScore = Math.max(0, Math.min(100, (currentScore * sampleWeight) + (50 * (1 - sampleWeight)) + conversionAdjustment));
        return {
            teacherName: row.teacherName,
            subjectName: row.subjectName,
            fairScore,
            conversionScore: SIG_toNumber(row.conversion.score, 50),
            sampleText: `${row.conversion.matchedCount || 0} / ${(SIG_toNumber(row.conversion.stabilityRate, 0) * 100).toFixed(0)}% | ${row.conversion.baselineCount || 0}次`,
            protectionText: row.teacherChangeProtected ? '已保护' : '正常',
            classesText: row.classesText
        };
    }), schoolName);

    return {
        rows: rows.sort((a, b) => b.fairScore - a.fairScore).slice(0, 12),
        assignmentCount: Object.keys(assignmentGroups).length
    };
}

function SIG_renderSummary(cache) {
    const grid = document.getElementById('sigSummaryGrid');
    if (!grid) return;
    const schoolCount = SIG_getAccessibleSchools().length;
    grid.innerHTML = `
        <div class="fb-card"><div class="fb-lbl">当前学校</div><div class="fb-val">${tmEscapeHtml(cache.schoolName || '未识别')}</div></div>
        <div class="fb-card"><div class="fb-lbl">本次实考</div><div class="fb-val">${cache.studentCount || 0}</div></div>
        <div class="fb-card"><div class="fb-lbl">历史期次</div><div class="fb-val">${cache.baselineExamCount || 0}</div></div>
        <div class="fb-card"><div class="fb-lbl">任课表</div><div class="fb-val">${cache.teacherReady ? '已加载' : '未加载'}</div></div>
        <div class="fb-card"><div class="fb-lbl">校内高水平线</div><div class="fb-val">${SIG_toNumber(cache.thresholdMeta.highLine, 0).toFixed(1)}</div></div>
        <div class="fb-card"><div class="fb-lbl">校内稳态线</div><div class="fb-val">${SIG_toNumber(cache.thresholdMeta.stableLine, 0).toFixed(1)}</div></div>
        <div class="fb-card"><div class="fb-lbl">学校数量</div><div class="fb-val">${schoolCount}</div></div>
        <div class="fb-card"><div class="fb-lbl">数据来源</div><div class="fb-val">${cache.source === 'upload' ? '专属文件' : '工作区'}</div></div>
    `;
}

function SIG_renderAdvice(cache) {
    const el = document.getElementById('sigAdviceList');
    const notice = document.getElementById('sigModeNotice');
    const diag = document.getElementById('sigDiagnosisHint');
    const badge = document.getElementById('sigSourceBadge');
    const status = document.getElementById('sigImportStatus');
    if (!el || !notice) return;
    const schoolCount = SIG_getAccessibleSchools().length;
    const items = [];
    if (cache.source === 'upload') items.push('当前使用本模块专属成绩文件，分析结果与母模块数据隔离。');
    else items.push('当前暂用本地工作区中已加载的校内成绩，建议尽快导入本模块专属文件。');
    if (schoolCount <= 1) items.push('当前数据只有本校口径，校际联考横向排名不适用。');
    else items.push('即使当前工作区有多校数据，本页也只按本校-only口径分析。');
    if (cache.baselineExamCount <= 0) items.push('当前没有可用历史考试，本页只输出当次诊断分。');
    else items.push(`当前已检测到 ${cache.baselineExamCount} 次历史考试，教师公平分会优先滚动参考最近 ${cache.rollingBaselineCount || 0} 次快照。`);
    if (cache.teacherAssignmentCount <= 0) items.push('当前未找到本校本地任课表映射，教师公平快览暂时无法展开。');
    else if (!cache.teacherRows.length) items.push('已识别到任课表映射，但当前权限下暂无可见的教师公平结果。');
    items.push('本页不调用云端保存，不会把校内月考数据同步到云端。');
    el.innerHTML = `<ul class="plain-list">${items.map((item) => `<li>${tmEscapeHtml(item)}</li>`).join('')}</ul>`;
    notice.textContent = cache.baselineExamCount > 0
        ? '当前使用校内公平口径：联考模块可参考，但本页更适合月考/校考。'
        : '当前使用当次校内诊断口径：只看本校执行状态，不输出正式联考绩效。';
    if (diag) {
        diag.innerHTML = `
            <ul class="plain-list">
                <li>当前来源：${tmEscapeHtml(cache.source === 'upload' ? '专属文件' : '工作区')}。</li>
                <li>当前学校：${tmEscapeHtml(cache.schoolName || '未识别')}，实考 ${cache.studentCount || 0} 人。</li>
                <li>当前更适合使用 ${tmEscapeHtml(cache.baselineExamCount > 0 ? '校内公平模式' : '当次诊断模式')}。</li>
                <li>任课表状态：${tmEscapeHtml(cache.teacherStatusText || '未加载')}。</li>
            </ul>
        `;
    }
    if (badge) badge.textContent = `当前来源：${cache.source === 'upload' ? '专属文件' : '工作区'}`;
    if (status && cache.source === 'workspace') {
        status.textContent = '尚未导入专属成绩文件。当前临时使用本地工作区中已加载的校内成绩，不会同步云端。';
    }
}

function SIG_renderTables(cache) {
    const classBody = document.querySelector('#sigClassTable tbody');
    const teacherBody = document.querySelector('#sigTeacherTable tbody');
    const baselineBody = document.querySelector('#sigBaselineTable tbody');
    if (classBody) {
        classBody.innerHTML = cache.classRows.length
            ? cache.classRows.map((row) => `
                <tr>
                    <td>${tmEscapeHtml(row.className)}</td>
                    <td>${row.count}</td>
                    <td>${row.avg.toFixed(2)}</td>
                    <td>${(row.highRate * 100).toFixed(1)}%</td>
                    <td>${(row.stableRate * 100).toFixed(1)}%</td>
                    <td style="font-weight:700; color:#6d28d9;">${row.score.toFixed(1)}</td>
                </tr>
            `).join('')
            : '<tr><td colspan="6" style="text-align:center; color:#999;">暂无可分析班级数据</td></tr>';
    }
    if (teacherBody) {
        teacherBody.innerHTML = cache.teacherRows.length
            ? cache.teacherRows.map((row) => `
                <tr>
                    <td>${tmEscapeHtml(row.teacherName)}</td>
                    <td>${tmEscapeHtml(row.subjectName)}</td>
                    <td>${tmEscapeHtml(row.classesText || '-')}</td>
                    <td>${row.fairScore.toFixed(1)}</td>
                    <td>${row.conversionScore.toFixed(1)}</td>
                    <td>${tmEscapeHtml(row.sampleText)}</td>
                    <td>${tmEscapeHtml(row.protectionText)}</td>
                </tr>
            `).join('')
            : '<tr><td colspan="7" style="text-align:center; color:#999;">暂无教师公平快览数据</td></tr>';
    }
    if (baselineBody) {
        baselineBody.innerHTML = cache.baselineSummary.length
            ? cache.baselineSummary.map((row) => `
                <tr>
                    <td>${tmEscapeHtml(row.examLabel)}</td>
                    <td>${tmEscapeHtml(row.createdAtText)}</td>
                    <td>${row.matchedCount} / ${(SIG_toNumber(row.matchedRate, 0) * 100).toFixed(0)}%</td>
                    <td>${row.sampleCount}</td>
                    <td>${row.subjectCount}</td>
                </tr>
            `).join('')
            : '<tr><td colspan="5" style="text-align:center; color:#999;">暂无可用历史基线数据</td></tr>';
    }
}

function SIG_render() {
    SIG_ensureLayout();
    const schoolName = SIG_updateSchoolSelect();
    SIG_syncSchoolSelect(schoolName);
    const source = SIG_getSourceState();
    const students = SIG_getSchoolStudents(schoolName);
    const classInfo = SIG_buildClassRows(students);
    const baselineExams = SIG_getBaselineExamEntries(schoolName);
    const teacherResult = SIG_buildTeacherRows(schoolName, students, baselineExams, source);
    const teacherReady = teacherResult.assignmentCount > 0;
    const baselineSummary = SIG_buildBaselineSummary(baselineExams, students);
    const teacherStatusText = teacherResult.assignmentCount <= 0
        ? '未加载'
        : (teacherResult.rows.length ? '已加载' : '受权限过滤');
    SIG_CACHE = {
        schoolName,
        source: source.source,
        localOnly: true,
        classRows: classInfo.rows,
        teacherRows: teacherResult.rows,
        baselineSummary,
        studentCount: students.length,
        baselineExamCount: baselineExams.length,
        rollingBaselineCount: Math.min(3, baselineExams.length),
        teacherReady,
        teacherStatusText,
        teacherAssignmentCount: teacherResult.assignmentCount,
        thresholdMeta: classInfo.thresholds
    };
    SIG_renderSummary(SIG_CACHE);
    SIG_renderAdvice(SIG_CACHE);
    SIG_renderTables(SIG_CACHE);
}

function SIG_export() {
    if (!SIG_CACHE.schoolName) SIG_render();
    if (!SIG_CACHE.schoolName) return alert('请先加载校内成绩分析');
    const wb = XLSX.utils.book_new();
    const summaryData = [
        ['学校', '模式', '来源', '实考人数', '历史期次', '任课表状态', '校内高水平线', '校内稳态线'],
        [
            SIG_CACHE.schoolName,
            SIG_CACHE.baselineExamCount > 0 ? '校内公平模式' : '当次诊断模式',
            SIG_CACHE.source === 'upload' ? '专属文件' : '工作区',
            SIG_CACHE.studentCount,
            SIG_CACHE.baselineExamCount,
            SIG_CACHE.teacherStatusText || (SIG_CACHE.teacherReady ? '已加载' : '未加载'),
            SIG_toNumber(SIG_CACHE.thresholdMeta.highLine, 0),
            SIG_toNumber(SIG_CACHE.thresholdMeta.stableLine, 0)
        ]
    ];
    const classData = [['班级', '实考', '均分', '校内高水平率', '校内稳态率', '诊断分']]
        .concat(SIG_CACHE.classRows.map((row) => [row.className, row.count, row.avg.toFixed(2), (row.highRate * 100).toFixed(2), (row.stableRate * 100).toFixed(2), row.score.toFixed(2)]));
    const teacherData = [['教师', '学科', '班级', '公平绩效', '转化分', '共同样本/稳定', '换老师保护']]
        .concat(SIG_CACHE.teacherRows.map((row) => [row.teacherName, row.subjectName, row.classesText || '', row.fairScore.toFixed(2), row.conversionScore.toFixed(2), row.sampleText, row.protectionText]));
    const baselineData = [['考试快照', '生成时间', '可比样本', '记录数', '学科数']]
        .concat((SIG_CACHE.baselineSummary || []).map((row) => [row.examLabel, row.createdAtText, `${row.matchedCount} / ${(SIG_toNumber(row.matchedRate, 0) * 100).toFixed(0)}%`, row.sampleCount, row.subjectCount]));
    XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet(summaryData), '校内摘要');
    XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet(classData), '班级执行表');
    XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet(teacherData), '教师公平快览');
    XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet(baselineData), '历次基线');
    XLSX.writeFile(wb, `${SIG_CACHE.schoolName || '本校'}_校内成绩分析.xlsx`);
}

let currentCategory = 'data';

function renderNavigation() {
    const sidebarNav = document.getElementById('sidebar-nav');
    if (!sidebarNav) return;

    sidebarNav.innerHTML = '';

    const role = (typeof Auth !== 'undefined' && Auth.currentUser) ? Auth.currentUser.role : 'guest';
    const restrictedRoles = ['teacher', 'class_teacher'];
    const isRestricted = restrictedRoles.includes(role);
    const isTeacherRole = (role === 'teacher' || role === 'class_teacher');

    if (isRestricted && (currentCategory === 'data' || currentCategory === 'tools')) {
        currentCategory = 'town';
        document.documentElement.style.setProperty('--primary', NAV_STRUCTURE['town'].color);
    }

    Object.keys(NAV_STRUCTURE).forEach(key => {
        const cat = NAV_STRUCTURE[key];

        // 权限过滤整块大类
        if (isRestricted && (key === 'data' || key === 'tools')) return;
        if (isTeacherRole && key === 'town') return;

        // 创建侧边栏主菜单项 (Parent Module)
        const catItem = document.createElement('div');
        catItem.className = 'sidebar-menu-item';

        if (key === currentCategory) {
            catItem.classList.add('active');
        }

        catItem.onmouseover = () => { if (key !== currentCategory) catItem.style.color = cat.color; };
        catItem.onmouseout = () => { if (key !== currentCategory) catItem.style.color = 'var(--secondary)'; };

        catItem.title = cat.title;
        catItem.innerHTML = `<i class="ti ${cat.icon}"></i><span>${cat.title}</span>`;

        catItem.onclick = (e) => {
            e.stopPropagation();
            if (currentCategory !== key) {
                switchCategory(key);
            }

            // On mobile, auto-close sidebar after click
            const sidebar = document.getElementById('app-sidebar');
            if (sidebar && sidebar.classList.contains('show-mobile')) {
                sidebar.classList.remove('show-mobile');
            }
        };

        sidebarNav.appendChild(catItem);
    });

    renderSubNavigation();
}

function renderSubNavigation() {
    const subNavContainer = document.getElementById('sub-nav-container');
    if (!subNavContainer) return;

    subNavContainer.innerHTML = '';

    const role = (typeof Auth !== 'undefined' && Auth.currentUser) ? Auth.currentUser.role : 'guest';
    const cat = NAV_STRUCTURE[currentCategory];
    if (!cat || !cat.items) return;

    const validItems = cat.items.filter(item => {
        if ((role === 'teacher' || role === 'class_teacher') && typeof canAccessModule === 'function' && !canAccessModule(item.id)) return false;
        if (role === 'teacher' && ['single-school-eval', 'exam-arranger', 'freshman-simulator'].includes(item.id)) return false;
        if (item.id === 'report-generator' && typeof CONFIG !== 'undefined' && !CONFIG.showQuery) return false;
        return true;
    });

    if (validItems.length === 0) return;

    validItems.forEach(item => {
        const chip = document.createElement('div');
        chip.className = 'chip-item';

        const targetElement = document.getElementById(item.id);
        const isActive = targetElement && targetElement.classList.contains('active');

        if (isActive) {
            chip.classList.add('active');
        }

        const cleanText = item.text.replace(/[\u{1F300}-\u{1F9FF}]/gu, '').trim();
        chip.title = cleanText;
        // 使用图标增强视觉
        chip.innerHTML = `<i class="ti ${item.icon}"></i><span>${cleanText}</span>`;

        chip.onclick = (e) => {
            e.stopPropagation();
            document.documentElement.style.setProperty('--primary', cat.color);
            switchTab(item.id);
            renderSubNavigation(); // Refresh chip active states
        };

        subNavContainer.appendChild(chip);
    });

    // 如果当前没有任何激活的section，自动激活可用的第一个模块
    setTimeout(() => {
        const hasActiveSection = document.querySelector('.section.active');
        if (!hasActiveSection && subNavContainer.querySelector('.chip-item')) {
            subNavContainer.querySelector('.chip-item').click();
        }
    }, 100);
}

function switchCategory(key) {
    currentCategory = key;
    document.documentElement.style.setProperty('--primary', NAV_STRUCTURE[key].color);
    forceHideAllSectionsExcept();
    resetMainViewport();
    renderNavigation();

    // Auto click first item of new category
    setTimeout(() => {
        const subNavContainer = document.getElementById('sub-nav-container');
        if (subNavContainer && subNavContainer.querySelector('.chip-item')) {
            subNavContainer.querySelector('.chip-item').click();
        }
    }, 50);
}

window.getCurrentNavCategory = function () {
    return currentCategory;
};

window.switchNavCategory = function (key) {
    switchCategory(key);
};

